mapper.select:
SELECT *
FROM schedule_blocks
WHERE schedule_block_id = #{scheduleBlockId}
  AND user_id           = #{userId}
  AND is_deleted        = 0

SELECT *
FROM schedule_blocks
WHERE user_id    = #{userId}
  AND is_deleted = 0
  AND block_date = #{blockDate}
ORDER BY start_time ASC

mapper.update:
UPDATE schedule_blocks
SET block_date    = #{blockDate},
    daily_plan_id = #{dailyPlanId},
    start_time    = #{startTime},
    end_time      = #{endTime}
WHERE schedule_block_id = #{scheduleBlockId}
  AND user_id           = #{userId}
  AND is_deleted        = 0

UPDATE schedule_blocks
SET title = #{title}
WHERE schedule_block_id = #{scheduleBlockId}
  AND user_id           = #{userId}
  AND is_deleted        = 0

UPDATE schedule_blocks
SET status = #{status}
WHERE schedule_block_id = #{scheduleBlockId}
  AND user_id           = #{userId}
  AND is_deleted        = 0

UPDATE schedule_blocks
SET status = 'DONE'
WHERE schedule_block_id = #{scheduleBlockId}
  AND user_id           = #{userId}
  AND is_deleted        = 0
  AND status IN ('PLANNED', 'HOLD')

UPDATE schedule_blocks
SET status = 'PLANNED'
WHERE schedule_block_id = #{scheduleBlockId}
  AND user_id           = #{userId}
  AND is_deleted        = 0
  AND status            = 'DONE'
